**Complete Gatling simulation:**

```java
public class PaymentLoadSimulation extends Simulation {
    // HTTP configuration:
    HttpProtocolBuilder httpProtocol = http
        .baseUrl("http://staging.razorpay.internal")
        .acceptHeader("application/json")
        .contentTypeHeader("application/json")
        .shareConnections();

    // Feeder: CSV with test data
    FeederBuilder.Batchable<String> merchantFeeder =
        csv("merchants.csv").random();

    // Scenario: payment processing flow
    ScenarioBuilder paymentScenario = scenario("Payment Processing")
        .feed(merchantFeeder)
        .exec(
            http("POST /api/payments")
                .post("/api/payments")
                .header("X-API-Key", "#{apiKey}")
                .body(StringBody("""
                    {"merchant_id": "#{merchantId}",
                     "amount": #{amount},
                     "gateway": "visa"}
                """))
                .check(
                    status().is(200),
                    jsonPath("$.status").is("PENDING"),
                    responseTimeInMillis().lt(500)  // each request < 500ms
                )
        )
        .pause(100.milliseconds, 500.milliseconds);

    // Load profile: warmup → ramp → sustain
    {
        setUp(
            paymentScenario.injectOpen(
                atOnceUsers(10),                         // baseline: 10 users immediately
                rampUsers(100).during(30),               // ramp to 100 users in 30s
                constantUsersPerSec(50).during(120)      // sustain 50 req/s for 2 minutes
            )
        ).protocols(httpProtocol)
         .assertions(
             global().responseTime().percentile(99).lt(200),    // p99 < 200ms
             global().responseTime().percentile(95).lt(120),    // p95 < 120ms
             global().successfulRequests().percent().gt(99.9),  // < 0.1% errors
             global().requestsPerSec().gt(45)                    // throughput > 45 req/s
         );
    }
}
```
